import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [42, 47, 52, 58, 65],
    options: {
      chart: {
        width: 380,
        type: 'polarArea',
      },
      labels: ['Free', 'Basic', 'Pro', 'Team', 'Enterprise'],
      title: {
        text: 'Satisfaction Score by Plan Tier',
        align: 'center',
      },
      fill: {
        opacity: 1,
      },
      stroke: {
        width: 1,
        colors: undefined,
      },
      yaxis: {
        show: false,
      },
      legend: {
        position: 'bottom',
      },
      plotOptions: {
        polarArea: {
          rings: {
            strokeWidth: 0,
          },
          spokes: {
            strokeWidth: 0,
          },
        },
      },
      theme: {
        monochrome: {
          enabled: true,
          shadeTo: 'light',
          shadeIntensity: 0.6,
        },
      },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="polarArea"
          width={380}
        />
      </div>
    </div>
  )
}

export default ApexChart
